/**
 * Sprout Design System — Input Component
 *
 * ✅ EXACT MATCH to Figma component "Input Form 1" (node: 31:1347)
 * Source page: ↪︎ Components · Figma file: EhpRiGZ5eJnBb132X9zewg
 *
 * Key values extracted directly from Figma (live scan):
 *   - Field frame cornerRadius: 10
 *   - Field fill Normal:   #EAE6DB  (VariableID:26:555 — secondary/600, darker cream)
 *   - Field fill Focused:  #EAE6DB  (same fill, focus shown via label color change)
 *   - Label font:  Playfair Display Medium, 12px, color #1E3E2B (brand/700)
 *   - Input font:  Inter Regular, 12px
 *   - Placeholder color: #7D7060  (VariableID:24:329 — warm grey)
 *   - Filled text color:  #1E3E2B  (VariableID:24:335 — brand/700)
 *   - Disabled text/label: #9AA3AD (VariableID:30:1322)
 *   - Error hint color:   #D64545  (VariableID:24:340 — error/500)
 *   - Field height: 57px, padding: 10px H / 8px V
 *   - Component total height (Large): 80px (label + field + hint)
 *
 * NOTE: Figma Input uses NO stroke border — the field is visually separated
 * from the cream page background (#F4F1EA) by its darker fill (#EAE6DB).
 * We add a subtle focus ring for usability since React Native needs it.
 */

import React, { useState } from 'react';
import {
  StyleSheet,
  Text,
  TextInput,
  TextInputProps,
  View,
  ViewStyle,
} from 'react-native';

// ─── Raw Figma-extracted values ───────────────────────────────────────────────

const FIGMA = {
  // Field background (VariableID:26:555 → secondary/600)
  fieldBg:          '#EAE6DB',
  fieldBgDisabled:  '#F0EDE5',  // slightly lighter when disabled

  // Corner radius — confirmed from inner "Input" frame
  cornerRadius:     10,

  // Padding on the field frame: l=10, r=10, t=8, b=8
  paddingH:         10,
  paddingV:         8,

  // Field heights per size
  fieldHeightLarge:  57,
  fieldHeightMedium: 50,
  fieldHeightSmall:  43,

  // Label above field — Playfair Display Medium, 12px
  labelFont:        'Playfair Display',
  labelFontWeight:  '500' as const,
  labelSize:        12,
  labelColor:       '#1E3E2B',  // VariableID:24:335 — brand/700

  // Input text — Inter Regular, 12px
  inputFont:        'Inter',
  inputFontWeight:  '400' as const,
  inputSize:        12,
  filledColor:      '#1E3E2B',  // same as label when filled / focused

  // Placeholder — Inter Regular, warm muted
  placeholderColor: '#7D7060',  // VariableID:24:329

  // Hint / helper text — Inter Regular, 12px
  hintColor:        '#7D7060',

  // Error — applied to hint text
  errorColor:       '#D64545',  // VariableID:24:340 — error/500

  // Disabled
  disabledColor:    '#9AA3AD',  // VariableID:30:1322

  // Focus ring (not in Figma — added for React Native usability)
  focusBorderColor: '#186338',  // brand/500
  focusBorderWidth: 1.5,
};

// ─── Types ───────────────────────────────────────────────────────────────────

export type InputSize   = 'Large' | 'Medium' | 'Small';

export interface InputProps extends Omit<TextInputProps, 'style'> {
  /** Label above the field (Playfair Display Medium) */
  label?: string;
  /** Placeholder text */
  placeholder?: string;
  /** Helper text below field */
  helperText?: string;
  /** Error message — overrides helperText and shows in error colour */
  errorText?: string;
  /** Size variant */
  size?: InputSize;
  /** Left icon */
  leftIcon?: React.ReactNode;
  /** Right icon */
  rightIcon?: React.ReactNode;
  /** Disabled state */
  disabled?: boolean;
  /** Container style */
  containerStyle?: ViewStyle;
}

// ─── Field height per size ────────────────────────────────────────────────────

const FIELD_HEIGHT: Record<InputSize, number> = {
  Large:  FIGMA.fieldHeightLarge,
  Medium: FIGMA.fieldHeightMedium,
  Small:  FIGMA.fieldHeightSmall,
};

// ─── Component ───────────────────────────────────────────────────────────────

export const Input: React.FC<InputProps> = ({
  label,
  placeholder,
  helperText,
  errorText,
  size = 'Large',
  leftIcon,
  rightIcon,
  disabled = false,
  containerStyle,
  onFocus,
  onBlur,
  value,
  ...rest
}) => {
  const [isFocused, setIsFocused] = useState(false);
  const hasError  = Boolean(errorText);
  const fieldH    = FIELD_HEIGHT[size];

  return (
    <View style={[styles.wrapper, containerStyle]}>

      {/* ── Label (Playfair Display Medium — confirmed from Figma) ── */}
      {label && (
        <Text
          style={[
            styles.label,
            {
              color: disabled
                ? FIGMA.disabledColor
                : FIGMA.labelColor,
            },
          ]}
          numberOfLines={1}
        >
          {label}
        </Text>
      )}

      {/* ── Field box ── */}
      <View
        style={[
          styles.fieldBox,
          {
            height:          fieldH,
            borderRadius:    FIGMA.cornerRadius,
            backgroundColor: disabled ? FIGMA.fieldBgDisabled : FIGMA.fieldBg,
            // Subtle focus ring — not in Figma but needed for React Native
            borderWidth:     isFocused && !disabled ? FIGMA.focusBorderWidth : 0,
            borderColor:     hasError
              ? FIGMA.errorColor
              : FIGMA.focusBorderColor,
            paddingHorizontal: FIGMA.paddingH,
            paddingVertical:   FIGMA.paddingV,
            opacity: disabled ? 0.6 : 1,
          },
        ]}
      >
        {leftIcon && (
          <View style={styles.iconLeft}>{leftIcon}</View>
        )}

        <TextInput
          style={[
            styles.textInput,
            {
              fontSize:   FIGMA.inputSize,
              fontFamily: FIGMA.inputFont,
              fontWeight: FIGMA.inputFontWeight,
              color:      disabled
                ? FIGMA.disabledColor
                : FIGMA.filledColor,
            },
          ]}
          placeholder={placeholder}
          placeholderTextColor={disabled ? FIGMA.disabledColor : FIGMA.placeholderColor}
          editable={!disabled}
          onFocus={e => { setIsFocused(true);  onFocus?.(e); }}
          onBlur ={e => { setIsFocused(false); onBlur?.(e);  }}
          value={value}
          {...rest}
        />

        {rightIcon && (
          <View style={styles.iconRight}>{rightIcon}</View>
        )}
      </View>

      {/* ── Hint / error text (Inter Regular, 12px) ── */}
      {(helperText || errorText) && (
        <Text
          style={[
            styles.hint,
            { color: hasError ? FIGMA.errorColor : FIGMA.hintColor },
          ]}
        >
          {errorText ?? helperText}
        </Text>
      )}
    </View>
  );
};

// ─── Styles ──────────────────────────────────────────────────────────────────

const styles = StyleSheet.create({
  wrapper: {
    gap: 4,
  },
  label: {
    fontSize:   FIGMA.labelSize,
    fontFamily: FIGMA.labelFont,
    fontWeight: FIGMA.labelFontWeight,
    lineHeight: FIGMA.labelSize * 1.5,
  },
  fieldBox: {
    flexDirection: 'row',
    alignItems:    'center',
  },
  textInput: {
    flex:          1,
    paddingVertical: 0,  // prevents extra Android padding
    height:        '100%',
  },
  iconLeft: {
    marginRight: 8,
  },
  iconRight: {
    marginLeft: 8,
  },
  hint: {
    fontSize:   FIGMA.inputSize,
    fontFamily: FIGMA.inputFont,
    fontWeight: FIGMA.inputFontWeight,
    lineHeight: FIGMA.inputSize * 1.5,
  },
});

export default Input;
